const StepProgress = () => <CippImageCard
    title="Onboarding Step"
    text="Please complete your company profile."
    imageUrl="/assets/illustrations/undraw_website_ij0l.svg"
    step={2}
    maxstep={5}
    linkText="Continue"
    link="/onboarding" />;

const InteractiveOffCanvas = () => {
    // eslint-disable-next-line react-hooks/rules-of-hooks
    const [open, setOpen] = useState(false)

    return (
        <>
            <Button variant="contained" onClick={() => setOpen(true)}>Open offcanvas
                        </Button>
            <CippOffCanvas
                onNavigateUp={fn()}
                onNavigateDown={fn()}
                title="Device Details"
                size="md"
                extendedData={mockDeviceData}
                extendedInfoFields={[
                  'displayName',
                  'userPrincipalName',
                  'mdeStatus',
                  'riskLevel',
                  'nested.osVersion',
                ]}
                canNavigateUp
                canNavigateDown
                footer={<button type="button">Force Sync</button>}
                visible={open}
                onClose={(...closeArgs) => {
                  setOpen(false)
                  args.onClose?.(...closeArgs)
                }}>{(data) => (
                  <div data-testid="custom-children">
                    <p>Investigate UPN: {data.userPrincipalName} in MDE Portal.</p>
                  </div>
                )}</CippOffCanvas>
        </>
    );
};

const SimpleColumns = () => <CippDataTable
    maxHeightOffset="100px"
    title="Users (Simple Columns)"
    data={richDataset.slice(0, 50)}
    simpleColumns={['displayName', 'mail', 'accountEnabled', 'department']} />;

const WithActions = () => <CippDataTable
    maxHeightOffset="100px"
    title="Users with Actions"
    data={richDataset.slice(0, 25)}
    simpleColumns={['displayName', 'userPrincipalName', 'accountEnabled', 'Status']}
    actions={[
      {
        label: 'View User',
        icon: <Visibility />,
        noConfirm: true,
        customFunction: fn(),
      },
      {
        label: 'Edit User',
        icon: <Edit />,
        noConfirm: true,
        customFunction: fn(),
      },
      {
        label: 'Block Sign-in',
        icon: <Block />,
        color: 'warning.main',
        noConfirm: true,
        customFunction: fn(),
      },
      {
        label: 'Delete User',
        icon: <Delete />,
        color: 'error.main',
        noConfirm: true,
        customFunction: fn(),
      },
    ]} />;

const WithOffCanvas = () => <CippDataTable
    maxHeightOffset="100px"
    title="Users with Off Canvas"
    data={richDataset.slice(0, 50)}
    simpleColumns={['displayName', 'userPrincipalName', 'department', 'accountEnabled']}
    offCanvas={{
      title: 'User Details',
      extendedInfoFields: [
        'displayName',
        'userPrincipalName',
        'mail',
        'department',
        'jobTitle',
        'accountEnabled',
        'createdDateTime',
      ],
    }}
    offCanvasOnRowClick />;

const WithActionsAndOffCanvas = () => <CippDataTable
    maxHeightOffset="100px"
    title="Users with Actions + Off Canvas"
    data={richDataset.slice(0, 25)}
    simpleColumns={['displayName', 'userPrincipalName', 'Status', 'accountEnabled']}
    actions={[
      {
        label: 'Edit User',
        icon: <Edit />,
        noConfirm: true,
        customFunction: fn(),
      },
    ]}
    offCanvas={{
      title: 'User Details',
      extendedInfoFields: ['displayName', 'userPrincipalName', 'mail', 'department'],
    }} />;

const SimpleMode = () => <CippDataTable
    maxHeightOffset="100px"
    title="Compact Table"
    data={richDataset.slice(0, 15)}
    simpleColumns={['displayName', 'mail', 'department']}
    simple />;

const WithFilters = () => <CippDataTable
    maxHeightOffset="100px"
    title="Filtered Users"
    data={richDataset.slice(0, 200)}
    simpleColumns={['displayName', 'department', 'Status', 'accountEnabled']}
    filters={[
      {
        id: 'department',
        value: 'Engineering',
      },
    ]} />;

const LoadingState = () => <CippDataTable
    maxHeightOffset="100px"
    title="Loading Users..."
    data={[]}
    isFetching
    simpleColumns={['displayName', 'mail', 'department']} />;

const DefaultSorting = () => <CippDataTable
    maxHeightOffset="100px"
    title="Sorted by Created Date"
    data={richDataset.slice(0, 100)}
    simpleColumns={['displayName', 'createdDateTime', 'department', 'Status']}
    defaultSorting={[{ id: 'createdDateTime', desc: true }]} />;

const WithConditionalActions = () => <CippDataTable
    maxHeightOffset="100px"
    title="Conditional Actions"
    data={richDataset.slice(0, 25)}
    simpleColumns={['displayName', 'accountEnabled', 'Status']}
    actions={[
      {
        label: 'Enable Account',
        icon: <CheckCircle />,
        noConfirm: true,
        customFunction: fn(),
        condition: (row) => row.accountEnabled === false,
      },
      {
        label: 'Block Sign-in',
        icon: <Block />,
        color: 'warning.main',
        noConfirm: true,
        customFunction: fn(),
        condition: (row) => row.accountEnabled === true,
      },
    ]} />;

const ArrayData = () => <CippDataTableButton
    onClick={fn()}
    title="View List"
    data={[
      { id: 1, name: 'Item 1' },
      { id: 2, name: 'Item 2' },
    ]}
    tableTitle="Items List" />;

const ObjectData = () => <CippDataTableButton
    onClick={fn()}
    title="View Details"
    data={{
      'Display Name': 'John Doe',
      Email: 'john@example.com',
    }}
    tableTitle="User Details" />;

const Primary = () => <ActionListItem
    icon={(<SvgIcon fontSize="small">
      <CheckCircleIcon />
    </SvgIcon>)}
    label="Check" />;

